module top_mod(
  input        clock,
  input        arst,
  output [9:0] _tmp16
);
  reg [9:0] state_9;
  wire [10:0] _GEN_0 = state_9 + 10'h1;
  assign _tmp16 = state_9;
  always @(posedge clock or posedge arst) begin
    if (arst) begin
      state_9 <= 10'h0;
    end else begin
      state_9 <= _GEN_0[9:0];
    end
  end
endmodule
